# Auto-populate the metrics section of a post-launch review document
import httpx
from datetime import datetime, timedelta

async def collect_review_metrics(
    feature_flag: str,
    start: datetime,
    end: datetime,
    baseline_start: datetime,
    baseline_end: datetime,
) -> dict:
    """Collect metrics for a post-launch review period vs a baseline period."""

    # Fetch from your metrics backend (Datadog, Prometheus, etc.)
    async with httpx.AsyncClient() as client:
        current = await client.get(
            "https://metrics-api/query",
            params={
                "feature_flag": feature_flag,
                "from": start.isoformat(),
                "to": end.isoformat(),
                "metrics": "error_rate,latency_p50,latency_p95,latency_p99,cost_per_request",
            },
        )
        baseline = await client.get(
            "https://metrics-api/query",
            params={
                "feature_flag": feature_flag,
                "from": baseline_start.isoformat(),
                "to": baseline_end.isoformat(),
                "metrics": "error_rate,latency_p50,latency_p95,latency_p99,cost_per_request",
            },
        )

    current_data = current.json()
    baseline_data = baseline.json()

    return {
        "period": {"from": start.isoformat(), "to": end.isoformat()},
        "error_rate": {
            "current": current_data["error_rate"],
            "baseline": baseline_data["error_rate"],
            "delta_pct": _pct_delta(
                baseline_data["error_rate"], current_data["error_rate"]
            ),
        },
        "latency_p95": {
            "current_ms": current_data["latency_p95"],
            "baseline_ms": baseline_data["latency_p95"],
            "delta_pct": _pct_delta(
                baseline_data["latency_p95"], current_data["latency_p95"]
            ),
        },
        "cost_per_request": {
            "current_usd": current_data["cost_per_request"],
            "baseline_usd": baseline_data["cost_per_request"],
            "delta_pct": _pct_delta(
                baseline_data["cost_per_request"], current_data["cost_per_request"]
            ),
        },
    }

def _pct_delta(baseline: float, current: float) -> float:
    if baseline == 0:
        return 0.0
    return round((current - baseline) / baseline * 100, 1)
